function zhUpdateNav(lang) {
  document.querySelectorAll('[data-zh-i18n]').forEach(function(el) {
    var key = el.getAttribute('data-zh-i18n');
    if (ZH_NAV_I18N[key] && ZH_NAV_I18N[key][lang]) {
      el.textContent = ZH_NAV_I18N[key][lang];
    }
  });
  var loginBtn = document.getElementById('zh-login-btn');
  if (loginBtn) loginBtn.textContent = lang==='kk'?'Кіру': lang==='en'?'Log in':'Войти';
}

/* ─── LANGUAGE SWITCHER ─── */
window.zhSetLang = function(lang) {
  if (typeof LANG !== 'undefined') LANG = lang;

  // Update topbar lang buttons
  document.querySelectorAll('.zh-lang-btn').forEach(function(b) {
    b.classList.toggle('active', b.dataset.lang === lang);
  });

  // Translate all nav data-zh-i18n labels
  zhUpdateNav(lang);

  var u = (typeof SESSION !== 'undefined' && SESSION && !SESSION.isGuest)
    ? Object.assign({}, SESSION, {lang: lang})
    : {id:'guest',name:'',email:'',city:'',diag:'',disabilityGroup:'',lang:lang,planDone:[],isGuest:true};

  if (typeof SESSION !== 'undefined' && SESSION && !SESSION.isGuest) {
    SESSION = u;
    if (typeof USERS !== 'undefined') USERS = USERS.map(function(x) { return x.id === u.id ? u : x; });
    if (typeof saveUsers === 'function') saveUsers();
    if (typeof saveSession === 'function') saveSession(u);
  } else {
    if (typeof GUEST_USER !== 'undefined') GUEST_USER.lang = lang;
  }

  // Re-render the dashboard (this re-renders ALL tab content in the current language)
  if (typeof renderDashboard === 'function') renderDashboard(u);
};

/* ─── AUTH UI UPDATE ─── */
function zhUpdateAuthUI() {
  var user = (typeof SESSION !== 'undefined') ? SESSION : null;
  var loginBtn  = document.getElementById('zh-login-btn');
  var logoutBtn = document.getElementById('zh-logout-btn');
  var userPill  = document.getElementById('zh-user-pill');
  var avatarEl  = document.getElementById('zh-user-avatar');
  var nameEl    = document.getElementById('zh-user-name');

  if (user && !user.isGuest && user.name) {
    if(loginBtn)  loginBtn.style.display  = 'none';
    if(logoutBtn) logoutBtn.style.display = 'inline-block';
    if(userPill)  userPill.style.display  = 'flex';
    var initials = user.name.split(' ').map(function(w){return w[0];}).join('').slice(0,2).toUpperCase();
    if(avatarEl) avatarEl.textContent = initials;
    if(nameEl)   nameEl.textContent   = user.name;
  } else {
    if(loginBtn)  loginBtn.style.display  = 'inline-block';
    if(logoutBtn) logoutBtn.style.display = 'none';
    if(userPill)  userPill.style.display  = 'none';
  }
}

/* ─── LOGOUT ─── */
window.zhLogout = function() {
  if (typeof SESSION !== 'undefined') SESSION = null;
  if (typeof clearSession === 'function') clearSession();
  if (typeof fireToast === 'function') fireToast('👋 ' + (zhLang()==='kk'?'Сәтті шықтыңыз':zhLang()==='en'?'Signed out':'Вы вышли'));
  zhUpdateAuthUI();
  var guest = {id:'guest',name:'',email:'',city:'',diag:'',disabilityGroup:'',lang:zhLang(),planDone:[],isGuest:true};
  if (typeof GUEST_USER !== 'undefined') GUEST_USER.lang = zhLang();
  if (typeof renderDashboard === 'function') setTimeout(function(){renderDashboard(guest);}, 350);
};

/* ─── BACK TO DASHBOARD ─── */
window.zhBackToDashboard = function() {
  var user = (typeof SESSION !== 'undefined' && SESSION && !SESSION.isGuest)
    ? SESSION
    : {id:'guest',name:'',email:'',city:'',diag:'',disabilityGroup:'',lang:zhLang(),planDone:[],isGuest:true};
  if (typeof renderDashboard === 'function') renderDashboard(user);
};

/* ─── OPEN PROFILE MODAL ─── */
window.zhOpenProfile = function() {
  if (typeof openProfileModal === 'function' && typeof SESSION !== 'undefined' && SESSION)
    openProfileModal(SESSION);
};

